2385								a_fmt		: FixFormat_t; 
2386								b			: std_logic_vector; 
2387								b_fmt		: FixFormat_t; 
2388								result_fmt	: FixFormat_t; 
2389								round		: FixRound_t	:= Trunc_s; 
2390								saturate	: FixSaturate_t := Warn_s) 
2391								return std_logic_vector is
2392			constant Saturate_c	: boolean := (saturate = Sat_s or
2393			-- synthesis translate_off
2394				saturate = Warn_s or
2395			-- synthesis translate_on
2396				saturate = SatWarn_s);
2397			constant Grow_c		: boolean := result_fmt.IntBits > max (a_fmt.IntBits, b_fmt.IntBits);
2398			-- Use correct signed/unsigned type for subtraction (else synthesis tools can cause problems)
2399			constant SubFmt_c 	: FixFormat_t := 
2400				(
2401					Signed		=> a_fmt.Signed or b_fmt.Signed,
2402					IntBits		=> max (a_fmt.IntBits, b_fmt.IntBits) + toInteger (Grow_c or Saturate_c),
2403					FracBits	=> max (a_fmt.FracBits, b_fmt.FracBits)
2404				);
2405			-- Switch to signed for final resize if saturating
2406			constant ReszFmt_c	: FixFormat_t := 
2407				(
2408					Signed		=> SubFmt_c.Signed or Saturate_c,
2409					IntBits		=> SubFmt_c.IntBits,
2410					FracBits	=> SubFmt_c.FracBits
2411				);
2412			constant SubWidth_c	: positive := cl_fix_width (SubFmt_c);
2413			variable a_v		: std_logic_vector (SubWidth_c-1 downto 0);
2414			variable b_v		: std_logic_vector (SubWidth_c-1 downto 0);
2415			variable temp_v		: std_logic_vector (SubWidth_c-1 downto 0);
2416			variable result_v	: std_logic_vector (cl_fix_width (result_fmt)-1 downto 0);
2417		begin
2418			a_v := cl_fix_resize (a, a_fmt, SubFmt_c, Trunc_s, None_s);
2419			b_v := cl_fix_resize (b, b_fmt, SubFmt_c, Trunc_s, None_s);
2420			temp_v := cl_fix_addsub_internal(a_v, a_fmt, b_v, b_fmt, '0');
2421			result_v := cl_fix_resize (temp_v, ReszFmt_c, result_fmt, round, saturate);
2422			return result_v;
2423		end;
