2447		--! cl_fix_saddsub implementation		
2448		function cl_fix_saddsub (	a			: std_logic_vector; 
2449									a_fmt		: FixFormat_t; 
2450									b			: std_logic_vector; 
2451									b_fmt		: FixFormat_t; 
2452									add			: std_logic;
2453									result_fmt	: FixFormat_t; 
2454									round		: FixRound_t	:= Trunc_s; 
2455									saturate	: FixSaturate_t := Warn_s) 
2456									return std_logic_vector is
2457			constant CarryBit_c : boolean := -- addition performed with an additional integer bit
2458				result_fmt.IntBits > max (a_fmt.IntBits, b_fmt.IntBits) or (saturate = Sat_s or
2459			-- synthesis translate_off
2460				saturate = Warn_s or
2461			-- synthesis translate_on
2462				saturate = SatWarn_s);
2463			constant TempFmt_c 	: FixFormat_t := 
2464				(
2465					Signed		=> a_fmt.Signed or b_fmt.Signed,
2466					IntBits		=> max (a_fmt.IntBits, b_fmt.IntBits) + toInteger (CarryBit_c), 
2467					FracBits	=> max (a_fmt.FracBits, b_fmt.FracBits)
2468				);
2469			constant TempWidth_c: positive := cl_fix_width (TempFmt_c);
2470			variable a_v		: std_logic_vector (TempWidth_c-1 downto 0);
2471			variable b_v		: std_logic_vector (TempWidth_c-1 downto 0);
2472			variable temp_v		: std_logic_vector (TempWidth_c-1 downto 0);
2473			variable result_v	: std_logic_vector (cl_fix_width (result_fmt)-1 downto 0);
2474		begin
2475			a_v := cl_fix_resize (a, a_fmt, TempFmt_c, Trunc_s, None_s);
2476			b_v := cl_fix_resize (b, b_fmt, TempFmt_c, Trunc_s, None_s);
2477			if to01 (add) = '0' then
2478				b_v := not b_v;
2479			end if;
2480			temp_v := cl_fix_addsub_internal(a_v, a_fmt, b_v, b_fmt, '1');
2481			result_v := cl_fix_resize (temp_v, TempFmt_c, result_fmt, round, saturate);
2482			return result_v;
2483		end;
