2488								a_fmt		: FixFormat_t; 
2489								b			: std_logic_vector; 
2490								b_fmt		: FixFormat_t; 
2491								result_fmt	: FixFormat_t; 
2492								round		: FixRound_t	:= Trunc_s; 
