2511		--! cl_fix_mean_angle implementation		
2512		function cl_fix_mean_angle (	a			: std_logic_vector; 
2513										a_fmt		: FixFormat_t; 
2514										b			: std_logic_vector; 
2515										b_fmt		: FixFormat_t; 
2516										precise		: boolean;
2517										result_fmt	: FixFormat_t; 
2518										round		: FixRound_t	:= Trunc_s; 
2519										saturate	: FixSaturate_t := Warn_s) 
2520										return std_logic_vector is
2521			constant TempFmt_c 	: FixFormat_t := 
2522				(
2523					Signed		=> a_fmt.Signed or b_fmt.Signed,
2524					IntBits		=> max (a_fmt.IntBits, b_fmt.IntBits) + 1, 
2525					FracBits	=> max (a_fmt.FracBits, b_fmt.FracBits)
2526				);
2527			constant TempWidth_c: positive := cl_fix_width (TempFmt_c);
2528			variable a_v		: std_logic_vector (cl_fix_width (a_fmt)-1 downto 0);
2529			variable b_v		: std_logic_vector (cl_fix_width (b_fmt)-1 downto 0);
2530			variable temp_v		: std_logic_vector (TempWidth_c-1 downto 0);
2531			variable result_v	: std_logic_vector (cl_fix_width (result_fmt)-1 downto 0);
2532			variable differentSigns_v	: boolean;
2533		begin
2534			assert a_fmt.Signed = b_fmt.Signed and a_fmt.IntBits = b_fmt.IntBits
2535				report "cl_fix_mean_angle : Signed and IntBits of 'a' and 'b' must be identical." 
2536				severity failure;
2537			assert cl_fix_width (a_fmt) >= 2 and cl_fix_width (b_fmt) >= 2
2538				report "cl_fix_mean_angle : The widths of 'a' and 'b' must be at least 2 bits each." 
2539				severity failure;
2540	
2541			a_v := a;
2542			b_v := b;
2543			differentSigns_v := a_v (a_v'high) /= b_v (b_v'high);
2544			if differentSigns_v and 
2545					a_v (a_v'high) /= a_v (a_v'high-1) and b_v (b_v'high) /= b_v (b_v'high-1) then
2546				a_v (a_v'high) := not a_v (a_v'high);
2547			end if;
2548			temp_v := cl_fix_add (a, a_fmt, b, b_fmt, TempFmt_c, Trunc_s, None_s);
2549			if precise and differentSigns_v and a_v (a_v'high-1) = b_v (b_v'high-1) and 
2550					temp_v (temp_v'high-2) = a_v (a_v'high-1) then
2551				temp_v (temp_v'high) := not temp_v (temp_v'high);
2552			end if;
2553			result_v := cl_fix_resize (temp_v, TempFmt_c, result_fmt, round, saturate);
2554			return result_v;
2555		end;
