2618		--! cl_fix_compare implementation
2619		function cl_fix_compare(	comparison	: string;
2620								a			: std_logic_vector;
2621								aFmt		: FixFormat_t;
2622								b			: std_logic_vector;
2623								bFmt		: FixFormat_t) return boolean is
2624			constant FullFmt_c	: FixFormat_t	:= (aFmt.Signed or bFmt.Signed, max(aFmt.IntBits, bFmt.IntBits), max(aFmt.FracBits, bFmt.FracBits));
2625			variable AFull_v	: std_logic_vector(cl_fix_width(FullFmt_c)-1 downto 0);
2626			variable BFull_v	: std_logic_vector(cl_fix_width(FullFmt_c)-1 downto 0);
2627		begin
2628			-- Check operator
2629			-- Convert to same type
2630			AFull_v	:= cl_fix_resize(a, aFmt, FullFmt_c);
2631			BFull_v := cl_fix_resize(b, bFmt, FullFmt_c);
2632			-- Convert to unsigned representation with offset
2633			if FullFmt_c.Signed then
2634				AFull_v(AFull_v'high) := not AFull_v(AFull_v'high);
2635				BFull_v(BFull_v'high) := not BFull_v(BFull_v'high);
2636			end if;
2637			-- Copare
2638			if 		comparison = "a=b" 	then return unsigned(AFull_v) = unsigned(BFull_v);
2639			elsif 	comparison = "a<b" 	then return unsigned(AFull_v) < unsigned(BFull_v);
2640			elsif	comparison = "a>b"	then return unsigned(AFull_v) > unsigned(BFull_v);
2641			elsif	comparison = "a<=b" then return unsigned(AFull_v) <= unsigned(BFull_v);
2642			elsif	comparison = "a>=b" then return unsigned(AFull_v) >= unsigned(BFull_v);
2643			elsif	comparison = "a!=b"	then return unsigned(AFull_v) /= unsigned(BFull_v);
2644			else	report "###ERROR###: cl_fix_compare illegal comparison type [" & comparison & "]" severity error;
2645					return false;
2646			end if;
2647			
2648		end function;	
2649	end;
